{
    "containers": [
        {
            "command": [
                "/bin/sh",
                "-c",
                "set -e\nfor i in $(seq 1 60); do\n  mc alias set local http://minio.elasticsearch.svc.cluster.local:9000 \"$MINIO_ROOT_USER\" \"$MINIO_ROOT_PASSWORD\" && break\n  sleep 2\ndone\nmc mb -p local/es-backups || true\n"
            ],
            "env": [
                {
                    "name": "MINIO_ROOT_USER",
                    "valueFrom": {
                        "secretKeyRef": {
                            "key": "rootUser",
                            "name": "minio-root"
                        }
                    }
                },
                {
                    "name": "MINIO_ROOT_PASSWORD",
                    "valueFrom": {
                        "secretKeyRef": {
                            "key": "rootPassword",
                            "name": "minio-root"
                        }
                    }
                }
            ],
            "image": "minio/mc:latest",
            "imagePullPolicy": "Always",
            "name": "mc",
            "resources": {},
            "terminationMessagePath": "/dev/termination-log",
            "terminationMessagePolicy": "File"
        }
    ],
    "dnsPolicy": "ClusterFirst",
    "restartPolicy": "OnFailure",
    "schedulerName": "default-scheduler",
    "securityContext": {},
    "terminationGracePeriodSeconds": 30
}

