input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type=strategic -p '{
  "spec": {
    "template": {
      "spec": {
        "initContainers": [
          {
            "name": "fix-permissions",
            "command": ["sh", "-c", "chown -R 1000:1000 /usr/share/elasticsearch/data"],
            "image": "busybox:1.35",
            "volumeMounts": [{"mountPath": "/usr/share/elasticsearch/data", "name": "data"}]
          },
          {
            "name": "keystore-setup",
            "image": "docker.elastic.co/elasticsearch/elasticsearch:8.11.1",
            "command": ["sh", "-c", "elasticsearch-keystore create -s; cat /secure-settings/s3.client.default.access_key | elasticsearch-keystore add --stdin -f s3.client.default.access_key; cat /secure-settings/s3.client.default.secret_key | elasticsearch-keystore add --stdin -f s3.client.default.secret_key; cp /usr/share/elasticsearch/config/elasticsearch.keystore /keystore/elasticsearch.keystore"],
            "securityContext": {"runAsUser": 1000},
            "volumeMounts": [
              {"name": "es-secure-settings-vol", "mountPath": "/secure-settings", "readOnly": true},
              {"name": "es-keystore-vol", "mountPath": "/keystore"}
            ]
          }
        ],
        "containers": [
          {
            "name": "elasticsearch",
            "volumeMounts": [
              {"name": "es-keystore-vol", "mountPath": "/usr/share/elasticsearch/config/elasticsearch.keystore", "subPath": "elasticsearch.keystore"},
              {"name": "es-config", "mountPath": "/usr/share/elasticsearch/config/elasticsearch.yml", "subPath": "elasticsearch.yml"},
              {"name": "es-certs", "mountPath": "/usr/share/elasticsearch/config/certs", "readOnly": true},
              {"name": "data", "mountPath": "/usr/share/elasticsearch/data"},
              {"name": "es-users", "mountPath": "/usr/share/elasticsearch/config/users", "subPath": "users"},
              {"name": "es-users", "mountPath": "/usr/share/elasticsearch/config/users_roles", "subPath": "users_roles"}
            ]
          }
        ],
        "volumes": [
          {"name": "es-keystore-vol", "emptyDir": {}},
          {"name": "es-secure-settings-vol", "secret": {"secretName": "es-secure-settings"}}
        ]
      }
    }
  }
}' 2>&1

