input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type=json -p '[
  {"op": "remove", "path": "/spec/template/spec/volumes/0"},
  {"op": "remove", "path": "/spec/template/spec/initContainers/1"},
  {"op": "remove", "path": "/spec/template/spec/containers/0/volumeMounts/0"},
  {"op": "add", "path": "/spec/template/spec/containers/0/volumeMounts/-", "value": {"mountPath": "/secure-settings", "name": "es-secure-settings-vol", "readOnly": true}},
  {"op": "add", "path": "/spec/template/spec/containers/0/lifecycle", "value": {
    "postStart": {
      "exec": {
        "command": ["sh", "-c", "until elasticsearch-keystore list 2>/dev/null; do sleep 2; done; cat /secure-settings/s3.client.default.access_key | elasticsearch-keystore add --stdin -f s3.client.default.access_key; cat /secure-settings/s3.client.default.secret_key | elasticsearch-keystore add --stdin -f s3.client.default.secret_key"]
      }
    }
  }}
]' 2>&1

