input.command:
kubectl patch statefulset es-data-nodes -n elasticsearch --type=json -p '[
  {"op": "add", "path": "/spec/template/spec/volumes/-", "value": {"name": "es-config-dir", "emptyDir": {}}},
  {"op": "add", "path": "/spec/template/spec/volumes/-", "value": {"name": "es-secure-settings-vol", "secret": {"secretName": "es-secure-settings"}}},
  {"op": "add", "path": "/spec/template/spec/initContainers/-", "value": {
    "name": "keystore-setup",
    "image": "docker.elastic.co/elasticsearch/elasticsearch:8.11.1",
    "command": ["sh", "-c", "cp -r /usr/share/elasticsearch/config/. /es-config/ && rm -f /usr/share/elasticsearch/config/elasticsearch.keystore && elasticsearch-keystore create && cat /secure-settings/s3.client.default.access_key | elasticsearch-keystore add --stdin -f s3.client.default.access_key && cat /secure-settings/s3.client.default.secret_key | elasticsearch-keystore add --stdin -f s3.client.default.secret_key && cp /usr/share/elasticsearch/config/elasticsearch.keystore /es-config/elasticsearch.keystore && chmod 600 /es-config/elasticsearch.keystore"],
    "volumeMounts": [
      {"name": "es-config-dir", "mountPath": "/es-config"},
      {"name": "es-secure-settings-vol", "mountPath": "/secure-settings", "readOnly": true}
    ]
  }},
  {"op": "add", "path": "/spec/template/spec/containers/0/volumeMounts/0", "value": {"name": "es-config-dir", "mountPath": "/usr/share/elasticsearch/config/"}}
]' 2>&1

